const PASS = "data:image/png;base,"

function getCookie(search) {
    let name = search + "=";
    let decodedCookie = decodeURIComponent(document.cookie);
    let fragments = decodedCookie.split(';');
    for(let i = 0; i <fragments.length; i++) {
        let chunk = fragments[i];
        while (chunk.charAt(0) == ' ') {
            chunk = chunk.substring(1);
        }
        if (chunk.indexOf(name) == 0) {
            return chunk.substring(name.length, chunk.length);
        }
    }
    return "";
}

// console.log(getCookie("access").length);

if (getCookie("access").length < 1 || PASS.match(new RegExp('[^' + getCookie("access") + ']', 'g')).join("") !== PASS) {
    location.href = "../CubeToPlay.github.io/login/page.html"
    // console.log("YES")
}